//#region src/lib/format.ts
var fmtCurrency = (n, currency = "INR") => new Intl.NumberFormat("en-IN", {
	style: "currency",
	currency,
	maximumFractionDigits: 0
}).format(Number(n ?? 0));
var fmtNumber = (n) => new Intl.NumberFormat("en-IN").format(Number(n ?? 0));
var fmtDate = (d) => {
	if (!d) return "—";
	return (typeof d === "string" ? new Date(d) : d).toLocaleDateString("en-IN", {
		day: "2-digit",
		month: "short",
		year: "numeric"
	});
};
//#endregion
export { fmtDate as n, fmtNumber as r, fmtCurrency as t };
